import React, { useState } from "react";

export default function ContactPanel({
  isOpen,
  onToggle,
  hovered,
  onHover,
  onLeave,
}) {
  const [sent, setSent] = useState(false);
  const [loading, setLoading] = useState(false);

  // Auto-ocultar mensaje de éxito
  React.useEffect(() => {
    if (sent) {
      const t = setTimeout(() => setSent(false), 4000);
      return () => clearTimeout(t);
    }
  }, [sent]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    e.stopPropagation();

    setLoading(true);

    const formData = new FormData(e.target);

    const res = await fetch("https://formspree.io/f/mnjlgkyw", {
      method: "POST",
      body: formData,
      headers: { Accept: "application/json" },
    });

    if (res.ok) {
      setSent(true);
      e.target.reset();
    }

    setLoading(false);
  };

  return (
    <div
      onClick={onToggle}
      onMouseEnter={() => onHover("right")}
      onMouseLeave={() => onLeave(null)}
      style={{
        flex: "1 1 360px",
        minWidth: "280px",
        background: "#fff",
        borderRadius: "18px",
        overflow: "hidden",
        cursor: "pointer",
        transition:
          "transform 0.2s ease, box-shadow 0.2s ease, min-height 0.3s ease",
        height: isOpen ? "auto" : "110px",
        boxShadow:
          hovered === "right"
            ? "0 12px 28px rgba(0,0,0,0.18)"
            : "0 6px 18px rgba(0,0,0,0.12)",
        transform: hovered === "right" ? "scale(1.015)" : "scale(1)",
        display: "flex",
        flexDirection: "column",
      }}
    >
      {/* TÍTULO */}
      <div
        style={{
          padding: "16px 20px 6px",
          fontFamily: "Montserrat, sans-serif",
          fontStyle: "italic",
          color: "#555",
          fontSize: "20px",
          lineHeight: 1.1,
          flexShrink: 0,
        }}
      >
        Consulta y Contacto
      </div>

      {/* CONTENIDO */}
      <div
        style={{
          padding: "0 20px 20px",
          color: "#666",
          fontSize: "14px",
          lineHeight: 1.4,
          overflow: "hidden",
          position: "relative",
        }}
      >
        {isOpen ? (
          <>
            <div style={{ marginTop: "18px" }}>
              Si tienes cualquier duda, consulta o aportación, puedes hacerlo
              desde aquí. Tus datos sólo se usarán para este fin.
            </div>

            {/* FORMULARIO */}
            <div
              style={{
                opacity: isOpen ? 1 : 0,
                maxHeight: isOpen ? "500px" : "0px",
                overflow: "hidden",
                transition: "opacity 0.25s ease, max-height 0.3s ease",
                pointerEvents: isOpen ? "auto" : "none",
                marginTop: isOpen ? "12px" : "0px",
              }}
            >
              <form
                onSubmit={handleSubmit}
                onClick={(e) => e.stopPropagation()}
                style={{
                  display: "flex",
                  flexDirection: "column",
                  gap: "8px",
                  maxWidth: "300px",
                }}
              >
                <input
                  type="email"
                  name="email"
                  placeholder="Tu email"
                  required
                  style={{
                    padding: "8px 10px",
                    borderRadius: "6px",
                    border: "1px solid #ccc",
                    fontSize: "13px",
                    fontFamily: "Montserrat, sans-serif",
                    outline: "none",
                  }}
                  onFocus={(e) =>
                    (e.target.style.border = "1px solid #0b1f4d")
                  }
                  onBlur={(e) =>
                    (e.target.style.border = "1px solid #ccc")
                  }
                />
                <textarea
                  name="message"
                  placeholder="Mensaje"
                  required
                  rows={4}
                  style={{
                    padding: "8px 10px",
                    borderRadius: "6px",
                    border: "1px solid #ccc",
                    fontSize: "13px",
                    fontFamily: "Montserrat, sans-serif",
                    outline: "none",
                    resize: "vertical",
                  }}
                  onFocus={(e) =>
                    (e.target.style.border = "1px solid #0b1f4d")
                  }
                  onBlur={(e) =>
                    (e.target.style.border = "1px solid #ccc")
                  }
                />
                <button
                  type="submit"
                  disabled={loading}
                  style={{
                    padding: "8px 12px",
                    borderRadius: "6px",
                    border: "1px solid #ccc",
                    background: "#fff",
                    fontSize: "13px",
                    fontFamily: "Montserrat, sans-serif",
                    cursor: "pointer",
                    transition: "all 0.2s ease",
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.background = "#f0f0f0";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.background = "#fff";
                  }}
                >
                  {loading ? "Enviando..." : "Enviar"}
                </button>
                {sent && (
                  <div
                    role="status"
                    aria-live="polite"
                    style={{
                      marginTop: "10px",
                      fontSize: "12px",
                      color: "#0b1f4d",
                      fontStyle: "italic",
                    }}
                  >
                    ✔ Mensaje enviado correctamente
                  </div>
                )}
              </form>
            </div>
          </>
        ) : (
          <div style={{ position: "relative" }}>
            <span style={{ display: "block" }}>
              Si tienes cualquier duda, consulta o aportación, puedes hacerlo
              desde aquí. Tus datos sólo se usarán para este fin.
            </span>
            {/* Degradado */}
            <div
              style={{
                position: "absolute",
                bottom: 0,
                left: 0,
                right: 0,
                height: "40px",
                background:
                  "linear-gradient(to bottom, rgba(255,255,255,0), rgba(255,255,255,1))",
                pointerEvents: "none",
              }}
            />
          </div>
        )}
      </div>
    </div>
  );
}
